UPDATE fish_collections SET location=#{location}, sub_location=#{subLocation}, name=#{name}, level=#{level},
    weather=#{weather}, time=#{time}, price_1=#{price1}, price_2=#{price2}, price_3=#{price3},
    price_4=#{price4}, price_5=#{price5}, size=#{size}, image_url=#{imageUrl}, event_name=#{eventName}
WHERE id=#{id}

